import React from 'react';
import ReactDOM from 'react-dom/client';
import './index.css';
import { initializeTheme, initializeLanguage } from './utils/theme';
import App from './App';

// Initialize theme and language before rendering
initializeTheme();
initializeLanguage();

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);
